import { fromOpenai } from 'instructor';
import { OpenAI } from 'openai';
import { z } from 'zod';

const EmailIntent = z.object({
  action: z.enum(['reply', 'forward', 'draft', 'archive']),
  priority: z.enum(['low', 'medium', 'high']).default('medium'),
  recipients: z.array(z.string())
});

const client = fromOpenai(new OpenAI());
const rawEmail = "Please reply to john@company.com about Q4 budget";
const intent = await client.chat.completions.create({
  model: 'gpt-4o-mini',
  messages: [{ role: 'user', content: rawEmail }],
  responseModel: EmailIntent
});
console.log(intent.action, intent.recipients);

import { fromOpenai } from 'instructor';
import { z } from 'zod';

const AttachmentInfo = z.object({
  filename: z.string(),
  content_type: z.enum(['pdf', 'docx', 'xlsx', 'image/png']),
  size_kb: z.number().int().min(1).max(25000),
  description: z.string().optional()
});

const client = fromOpenai(new OpenAI());
const attachments = await client.chat.completions.create({
  model: 'gpt-4o-mini',
  messages: [{ role: 'user', content: 'Email mentions Q4_budget.pdf and org_chart.xlsx' }],
  responseModel: z.array(AttachmentInfo)
});
console.log(attachments.map(a => a.filename));

