import { verify } from 'vex-sdk';
import { fromOpenai } from 'instructor';
import { z } from 'zod';

const EmailDraftSchema = z.object({
  subject: z.string(),
  body: z.string(),
  to: z.array(z.string().email())
});

const generateDraft = verify(
  async (prompt: string) => {
    const client = fromOpenai(new OpenAI());
    return client.chat.completions.create({
      model: 'gpt-4o',
      messages: [{ role: 'user', content: prompt }],
      responseModel: EmailDraftSchema
    });
  },
  {
    policies: ['block-pii', 'professional-tone', 'valid-emails'],
    maxRetries: 3
  }
);

const draft = await generateDraft('Draft professional reply about budget');
